qry:select.qry:xquery:
				for $r in sql('
				SELECT 
					VIS01_VISITAS.f_fechahora_ent_es
				FROM 
					VIS01_VISITAS_VIS,
					VIS01_VISITAS
				JOIN
				  VIS01_VISITAS_VIS.oi_visita INNER VIS01_VISITAS.oi_visita
				WHERE 

					VIS01_VISITAS.f_fechahora_ent_es >= {DateTime(#PARAM:@f_des)}
					AND 
					VIS01_VISITAS.f_fechahora_ent_es <= {DateTime(Number(DateTime(#PARAM:@f_has))+1)}								

					{%? (#PARAMIN:@oi_visitante!='') 
						{% AND VIS01_VISITAS_VIS.oi_visitante = {#PARAMIN:@oi_visitante} %} 
						{%  %} 
					%}													
					{%? (#PARAMIN:@oi_personal_aut!='') 
					  {% AND VIS01_VISITAS.oi_personal_aut = {#PARAMIN:@oi_personal_aut}%} 
					  {% %} 
					%}
					{%? (#PARAMIN:@oi_personal_vis!='') 
					  	{% AND VIS01_VISITAS.oi_personal_vis = {#PARAMIN:@oi_personal_vis}%} 
					  	{% %} 
					%}  
					{%? (#PARAMIN:@estado_vis = '1' )
					{% AND
						(
							(
							ISNOTNULL(VIS01_VISITAS_VIS.f_fechahora_ent)
							AND 
							ISNULL(VIS01_VISITAS_VIS.f_fechahora_sal)
							AND
							VIS01_VISITAS_VIS.f_fechahora_sal_es >= now()
							)
							OR
							( 
							ISNOTNULL(VIS01_VISITAS_VIS.f_fechahora_ent)
							AND 
							ISNULL(VIS01_VISITAS_VIS.f_fechahora_sal)
							AND
							ISNULL(VIS01_VISITAS_VIS.f_fechahora_sal_es)
							) 
						)
					%} 
					{% %} 
					%}

        	{%? (#PARAMIN:@estado_vis = '2' )
					{% AND
						(
						  (
							  VIS01_VISITAS.f_fechahora_ent_es >= now()
							  AND
							  ISNULL(VIS01_VISITAS_VIS.f_fechahora_ent)
						  )
						  OR
						  (  
						  	VIS01_VISITAS.f_fechahora_ent_es >= now()
						  	AND
							  ISNULL(VIS01_VISITAS_VIS.f_fechahora_ent)
							  AND 
							  ISNULL(VIS01_VISITAS_VIS.f_fechahora_sal)
						  )
						)
					%} 
					{% %} 
					%} 

					{%? (#PARAMIN:@estado_vis = '3' )
					{% AND 
						(
							(
							VIS01_VISITAS.f_fechahora_ent_es <= now()
							AND
							ISNULL(VIS01_VISITAS_VIS.f_fechahora_sal)
							AND
							ISNULL(VIS01_VISITAS_VIS.f_fechahora_ent)
							)
						) 
					%} 
					{% %} 
					%} 

					{%? (#PARAMIN:@estado_vis = '4' )
					{% AND 
						(
							(
							 ISNOTNULL(VIS01_VISITAS_VIS.f_fechahora_sal)
							)
						) 
					%} 
					{% %} 
					%} 

					{%? (#PARAMIN:@estado_vis = '5' )
					{%	AND
						(
							(
							ISNOTNULL(VIS01_VISITAS_VIS.f_fechahora_ent)
							AND
							VIS01_VISITAS_VIS.f_fechahora_sal_es <= now()
							AND
							ISNULL(VIS01_VISITAS_VIS.f_fechahora_sal)
							)
       			)
		      %} 
					{% %} 
					%}
				 GROUP BY VIS01_VISITAS.f_fechahora_ent_es				
			')/ROWS/ROW

				for $r in sql('
				SELECT 
					VIS01_VISITAS_VIS.oi_visita_vis,
					VIS01_VISITAS_VIS.f_fechahora_ent,
					VIS01_VISITAS_VIS.f_fechahora_sal,
					VIS01_VISITAS_VIS.f_fechahora_sal_es,
					VIS01_VISITAS.f_fechahora_ent_es,
					VIS01_VISITAS_VIS.oi_visita,
					VIS01_VISITAS_VIS.oi_visitante,
					VIS01_VISITAS.oi_personal_vis
				FROM 
					VIS01_VISITAS_VIS,
					VIS01_VISITAS
				JOIN
				  VIS01_VISITAS_VIS.oi_visita INNER VIS01_VISITAS.oi_visita
				WHERE 

					VIS01_VISITAS.f_fechahora_ent_es >= {DateTime(#PARAM:@fecha)}
					AND 
					VIS01_VISITAS.f_fechahora_ent_es <= {DateTime(Number(DateTime(#PARAM:@fecha))+1)}

          {%? (#PARAMIN:@oi_visitante!='') 
						{% AND VIS01_VISITAS_VIS.oi_visitante = {#PARAMIN:@oi_visitante} %} 
						{%  %} 
					%}													
					{%? (#PARAMIN:@oi_personal_aut!='') 
					  {% AND VIS01_VISITAS.oi_personal_aut = {#PARAMIN:@oi_personal_aut}%} 
					  {% %} 
					%}
					{%? (#PARAMIN:@oi_personal_vis!='') 
					  	{% AND VIS01_VISITAS.oi_personal_vis = {#PARAMIN:@oi_personal_vis}%} 
					  	{% %} 
					%}
					{%? (#PARAMIN:@estado_vis = '1' )
					{% AND
						(
							(
							ISNOTNULL(VIS01_VISITAS_VIS.f_fechahora_ent)
							AND 
							ISNULL(VIS01_VISITAS_VIS.f_fechahora_sal)
							AND
							VIS01_VISITAS_VIS.f_fechahora_sal_es >= now()
							)
							OR
							( 
							ISNOTNULL(VIS01_VISITAS_VIS.f_fechahora_ent)
							AND 
							ISNULL(VIS01_VISITAS_VIS.f_fechahora_sal)
							AND
							ISNULL(VIS01_VISITAS_VIS.f_fechahora_sal_es)
							) 
						)
					%} 
					{% %} 
					%}

        	{%? (#PARAMIN:@estado_vis = '2' )
					{% AND
						(
						  (
							  VIS01_VISITAS.f_fechahora_ent_es >= now()
							  AND
							  ISNULL(VIS01_VISITAS_VIS.f_fechahora_ent)
						  )
						  OR
						  (  
						  	VIS01_VISITAS.f_fechahora_ent_es >= now()
						  	AND
							  ISNULL(VIS01_VISITAS_VIS.f_fechahora_ent)
							  AND 
							  ISNULL(VIS01_VISITAS_VIS.f_fechahora_sal)
						  )
						)
					%} 
					{% %} 
					%} 

					{%? (#PARAMIN:@estado_vis = '3' )
					{% AND 
						(
							(
							VIS01_VISITAS.f_fechahora_ent_es <= now()
							AND
							ISNULL(VIS01_VISITAS_VIS.f_fechahora_sal)
							AND
							ISNULL(VIS01_VISITAS_VIS.f_fechahora_ent)
							)
						) 
					%} 
					{% %} 
					%} 

					{%? (#PARAMIN:@estado_vis = '4' )
					{% AND 
						(
							(
							 ISNOTNULL(VIS01_VISITAS_VIS.f_fechahora_sal)
							)
						) 
					%} 
					{% %} 
					%} 

					{%? (#PARAMIN:@estado_vis = '5' )
					{%	AND
						(
							(
							ISNOTNULL(VIS01_VISITAS_VIS.f_fechahora_ent)
							AND
							VIS01_VISITAS_VIS.f_fechahora_sal_es <= now()
							AND
							ISNULL(VIS01_VISITAS_VIS.f_fechahora_sal)
							)
       			)
		      %} 
					{% %} 
					%}
				ORDER BY oi_personal_vis ASC
			')/ROWS/ROW

for $r in SQL(' SELECT PER02_PERSONAL_EMP.e_numero_legajo, PER01_PERSONAL.d_ape_y_nom, VIS01_VISITAS.d_empresa_vis, ORG03_EMPRESAS.d_empresa, ORG03_EMPRESAS.c_empresa
FROM PER02_PERSONAL_EMP, PER01_PERSONAL, VIS01_VISITAS, VIS01_VISITAS_VIS, ORG03_EMPRESAS JOIN PER02_PERSONAL_EMP.oi_personal INNER PER01_PERSONAL.oi_personal, PER02_PERSONAL_EMP.oi_personal_emp INNER VIS01_VISITAS.oi_personal_vis, VIS01_VISITAS_VIS.oi_visita INNER VIS01_VISITAS.oi_visita, PER02_PERSONAL_EMP.oi_empresa INNER ORG03_EMPRESAS.oi_empresa WHERE VIS01_VISITAS.oi_visita = {#PARAM:@oi_visita}
{%? (#PARAMIN:@oi_personal_vis!='') {% AND VIS01_VISITAS.oi_personal_vis = {#PARAMIN:@oi_personal_vis}%} {% %} %} ORDER BY c_empresa ASC ')/ROWS/ROW
